function escFilter(v) {
  return String(v).replace(/\\/g, '\\\\').replace(/"/g, '\\"');
}

migrate(
  (app) => {
    let tenant;
    try {
      tenant = app.findFirstRecordByFilter('tenants', 'slug = "movexum"');
    } catch (e) {
      return; // ingen movexum-tenant (t.ex. tom dev-db) — hoppa över seed
    }
    const tenantId = tenant.id;
    const startupsCol = app.findCollectionByNameOrId('startups');
    const finCol = app.findCollectionByNameOrId('startup_financials');
    const syncedAt = new Date().toISOString();

    for (const c of DATA) {
      // ── Upsert startups-raden (uppslag på tenant + org_nr) ──────────
      let startup = null;
      try {
        startup = app.findFirstRecordByFilter(
          'startups',
          `tenant = "${tenantId}" && org_nr = "${escFilter(c.org_nr)}"`
        );
      } catch (e) {
        startup = null;
      }

      if (startup) {
        // Behåll staff-satt phase/status; uppdatera bara registerfälten.
        if (c.kommun) startup.set('kommun', c.kommun);
        if (c.bolag_status) startup.set('bolag_status', c.bolag_status);
        if (c.intagsdatum) startup.set('intagsdatum', c.intagsdatum);
        if (c.avslutsdatum) startup.set('avslutsdatum', c.avslutsdatum);
        app.save(startup);
      } else {
        const rec = new Record(startupsCol, {
          tenant: tenantId,
          name: c.name,
          org_nr: c.org_nr,
          status: c.status,
          phase: 'idea'
        });
        if (c.kommun) rec.set('kommun', c.kommun);
        if (c.bolag_status) rec.set('bolag_status', c.bolag_status);
        if (c.intagsdatum) rec.set('intagsdatum', c.intagsdatum);
        if (c.avslutsdatum) rec.set('avslutsdatum', c.avslutsdatum);
        app.save(rec);
        startup = rec;
      }

      // ── Upsert startup_financials per (startup, year) ───────────────
      for (const f of c.financials) {
        let fin = null;
        try {
          fin = app.findFirstRecordByFilter(
            'startup_financials',
            `startup = "${startup.id}" && year = ${f.year}`
          );
        } catch (e) {
          fin = null;
        }
        const target = fin || new Record(finCol, {});
        target.set('tenant', tenantId);
        target.set('startup', startup.id);
        target.set('year', f.year);
        target.set('source', 'import_excel');
        target.set('synced_at', syncedAt);
        if (f.employees !== null) target.set('employees', f.employees);
        if (f.revenue_sek !== null) target.set('revenue_sek', f.revenue_sek);
        if (f.personnel_cost_sek !== null) target.set('personnel_cost_sek', f.personnel_cost_sek);
        if (f.corporate_tax_sek !== null) target.set('corporate_tax_sek', f.corporate_tax_sek);
        app.save(target);
      }
    }
  },
  (app) => {
    // Ned-migration: medvetet no-op. Seedad bolagsdata kan ha redigerats av
    // staff efter import — vi raderar den inte automatiskt (ISO 27001 A.8.32,
    // undvik destruktiv rollback av domändata).
  }
);
